#[async_trait]
impl<R: UserQuotaProjectionRepository> UserQuotaEventHandler for UserQuotaProjector<R> {

    async fn on_created(&self, event: UserQuotaCreatedEvent, sequence: i64) -> Result<()> {
        let mut projection = UserQuotaProjection::new(
            event.id,
            event.user_id,
            event.limit_bytes,
            event.used_bytes,
            event.file_count,
            event.max_file_size,
            event.max_file_count,
            event.tier,
            event.quota_status,
            event.warning_threshold_percent,
            event.last_warning_sent_at,
            event.peak_usage_bytes,
            event.peak_usage_at,
            event.metadata
        );

        // Track the event sequence for this projection
        projection.apply_event(sequence);

        self.repository.save(&projection).await
    }

    async fn on_updated(&self, event: UserQuotaUpdatedEvent, sequence: i64) -> Result<()> {
        if let Some(mut projection) = self.repository.find_by_id(event.id).await? {
            // Apply updates from event
            projection.user_id = event.user_id;
            projection.limit_bytes = event.limit_bytes;
            projection.used_bytes = event.used_bytes;
            projection.file_count = event.file_count;
            projection.max_file_size = event.max_file_size;
            projection.max_file_count = event.max_file_count;
            projection.tier = event.tier;
            projection.quota_status = event.quota_status;
            projection.warning_threshold_percent = event.warning_threshold_percent;
            projection.last_warning_sent_at = event.last_warning_sent_at;
            projection.peak_usage_bytes = event.peak_usage_bytes;
            projection.peak_usage_at = event.peak_usage_at;
            projection.metadata = event.metadata;
            // Track the event sequence for this projection
            projection.apply_event(sequence);

            self.repository.save(&projection).await?;
        }

        Ok(())
    }

    async fn on_deleted(&self, event: UserQuotaDeletedEvent, _sequence: i64) -> Result<()> {
        self.repository.delete(event.id).await
    }
}

